sol! {
    event Delivered(bytes32 indexed jobId, address indexed user, address indexed target, bool success, uint256 gasConsumed, uint256 gasRefunded, uint256 valueRefunded);
    event DeliveryFailed(bytes32 indexed jobId, address indexed user, string reason);
}

pub enum DeliveryGasResult {
    Delivered { callback_gas: u64, job_id: B256, success: bool },
    Failed { job_id: B256 },
    EventNotFound,
}

pub fn extract_delivery_callback_gas(logs: &[Log], delivery_address: Address) -> DeliveryGasResult {
    for log in logs {
        if log.address != delivery_address { continue; }
        if log.topics().is_empty() { continue; }
        if log.topics()[0] == Delivered::SIGNATURE_HASH {
            if let Ok(event) = Delivered::decode_log(log) {
                match event.gasConsumed.try_into() {
                    Ok(gas) => return DeliveryGasResult::Delivered { callback_gas: gas, job_id: event.jobId, success: event.success },
                    Err(_) => continue,
                }
            }
        }
        if log.topics()[0] == DeliveryFailed::SIGNATURE_HASH {
            if let Ok(event) = DeliveryFailed::decode_log(log) {
                return DeliveryGasResult::Failed { job_id: event.jobId };
            }
        }
    }
    DeliveryGasResult::EventNotFound
}

pub fn get_delivery_callback_gas_or_fallback(result: &DeliveryGasResult, fallback: u64) -> u64 {
    match result {
        DeliveryGasResult::Delivered { callback_gas, .. } => *callback_gas,
        DeliveryGasResult::Failed { .. } | DeliveryGasResult::EventNotFound => fallback,
    }
}

